parameters.content:
## Send OTP Email
Sends OTP verification email to each member.
Expects: { notification_id, members: [{ first_name, email, otp }] }

parameters.jsCode:
const body = $input.first().json.body;
const notificationId = body.notification_id;

return body.members.map(member => ({
  json: {
    notification_id: notificationId,
    first_name: member.first_name || 'Participant',
    email: member.email || '',
    otp: member.otp || ''
  }
}));

const member = $input.item.json;
const name = (member.first_name || 'Participant').trim();
const otp = member.otp || '------';

const digits = String(otp).split('');
// Each digit tile: fluid width using a table-cell approach
// 6 digits + 5 gaps of 6px each must fit in ~300px min content width
// So each tile = ~44px max, font 28px — scales on desktop via container
const digitSpans = digits.map(d =>
  `<td style="width:44px; height:56px; text-align:center; vertical-align:middle; background:rgba(255,255,255,0.13); border-radius:8px; font-size:28px; font-weight:800; color:#ffffff; font-family:'Courier New',monospace; padding:0 4px;">${d}</td>`
).join('<td style="width:8px;"></td>');

const htmlBody = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    body { font-family: Arial, sans-serif; background-color: #f0f2f5; color: #333; -webkit-text-size-adjust: 100%; }
    .wrapper { background-color: #f0f2f5; padding: 24px 12px; }
    .container { max-width: 520px; margin: 0 auto; background-color: #ffffff; border-radius: 16px; overflow: hidden; box-shadow: 0 4px 24px rgba(0,0,0,0.10); width: 100%; }

    .header { background: linear-gradient(135deg, #0a2e2a 0%, #0d4a42 60%, #0f5c52 100%); padding: 32px 24px 26px; text-align: center; }
    .header-title { color: #ffffff; font-size: 22px; font-weight: 700; letter-spacing: 1px; }
    .header-subtitle { color: #7ecfc4; font-size: 11px; margin-top: 6px; letter-spacing: 2.5px; text-transform: uppercase; }

    .body { padding: 28px 24px; }
    .greeting { font-size: 17px; font-weight: 700; color: #111; margin-bottom: 12px; }
    .message { font-size: 14px; color: #555; line-height: 1.75; margin-bottom: 28px; }

    .otp-label { font-size: 11px; color: #999; text-transform: uppercase; letter-spacing: 2px; text-align: center; margin-bottom: 14px; }
    .otp-box { background: linear-gradient(135deg, #0a2e2a, #0f5c52); border-radius: 14px; padding: 28px 16px; text-align: center; margin-bottom: 28px; }
    .otp-table { border-collapse: separate; border-spacing: 0; margin: 0 auto; }
    .otp-validity { font-size: 12px; color: #7ecfc4; margin-top: 16px; letter-spacing: 0.3px; }

    .divider { border: none; border-top: 1px solid #f0f0f0; margin: 0 0 22px; }

    .warning { background-color: #fffbef; border-left: 3px solid #f0a500; padding: 12px 14px; border-radius: 6px; margin-bottom: 24px; }
    .warning p { font-size: 13px; color: #7a5c00; line-height: 1.65; }

    .help { font-size: 13px; color: #666; line-height: 1.7; }
    .help a { color: #0d4a42; font-weight: 600; text-decoration: none; }

    .footer { background-color: #f7f8f9; border-top: 1px solid #ececec; padding: 20px 24px; text-align: center; }
    .footer p { font-size: 11px; color: #bbb; line-height: 1.9; }
    .footer a { color: #0d4a42; font-weight: 600; text-decoration: none; }
  </style>
</head>
<body>
  <div class="wrapper">
    <div class="container">

      <div class="header">
        <div class="header-title">Supershyft</div>
        <div class="header-subtitle">Precision Health Solutions</div>
      </div>

      <div class="body">
        <p class="greeting">Hi ${name},</p>
        <p class="message">
          You requested a one-time password to access your Supershyft account.
          Use the code below to complete your verification.
          This code is valid for <strong>10 minutes</strong>.
        </p>

        <p class="otp-label">Your One-Time Password</p>
        <div class="otp-box">
          <table class="otp-table" cellpadding="0" cellspacing="0" role="presentation">
            <tr>${digitSpans}</tr>
          </table>
          <div class="otp-validity">Valid for 10 minutes &bull; Do not share this code</div>
        </div>

        <hr class="divider">

        <div class="warning">
          <p>&#x26a0;&#xfe0f;&nbsp; <strong>Security notice:</strong> Supershyft will never ask for your OTP over call or message. If you did not request this code, please ignore this email or contact our support team immediately.</p>
        </div>

        <p class="help">Need help? Reach us at <a href="mailto:support@supershyft.com">support@supershyft.com</a></p>
      </div>

      <div class="footer">
        <p>Warm regards,<br><strong style="color:#444;">Support Team - Supershyft</strong></p>
        <p style="margin-top:10px;"><a href="https://www.supershyft.com">www.supershyft.com</a></p>
        <p style="margin-top:10px;">This is an automated email. Please do not reply directly to this message.</p>
      </div>

    </div>
  </div>
</body>
</html>`;

return {
  json: {
    notification_id: member.notification_id,
    to: member.email,
    subject: `Your Supershyft verification code`,
    htmlBody
  }
};
